 13→namespace AssembleMonitor.Features.IoMonitor;
 14→
 15→/// <summary>
 16→/// I/O 모니터 뷰모델 — PLC 비트 데이터 실시간 표시 + 출력 제어
 17→/// </summary>
 18→public class IoMonitorViewModel : INotifyPropertyChanged, IDisposable
 19→{
 20→    private readonly XgtClient _client = new();
 21→    private CancellationTokenSource? _cts;
 22→
 23→    // 탭별 WORD 데이터
 24→    public ObservableCollection<WordViewModel> InputWords { get; } = [];
 25→    public ObservableCollection<WordViewModel> OutputWords { get; } = [];
