 27→
 28→    // 출력 캐시 — 토글 시 현재 값 기반으로 비트 변경 후 쓰기
 29→    private readonly ushort[] _outputCache = new ushort[10];
 30→
 31→    // 서보 파라미터 (DINT 값)
 32→    private int _targetPos, _targetVel, _jogVel, _actPos, _actVel;
 33→    private ushort _errCode, _actPosDeg;
 34→
 35→    public int TargetPos { get => _targetPos; set { _targetPos = value; OnPropertyChanged(); } }
 36→    public int TargetVel { get => _targetVel; set { _targetVel = value; OnPropertyChanged(); } }
 37→    public int JogVel { get => _jogVel; set { _jogVel = value; OnPropertyChanged(); } }
 38→    public int ActPos { get => _actPos; set { _actPos = value; OnPropertyChanged(); } }
 39→    public int ActVel { get => _actVel; set { _actVel = value; OnPropertyChanged(); } }
 40→    public ushort ErrCode { get => _errCode; set { _errCode = value; OnPropertyChanged(); } }
 41→    public ushort ActPosDeg { get => _actPosDeg; set { _actPosDeg = value; OnPropertyChanged(); } }
 42→
 43→    // Heartbeat 카운터 (MW500: bit0~7=카운터, bit8=PC_READY)
 44→    private byte _heartbeatCount;
 45→
 46→    // PLC 상태 (MW501 파싱)
 47→    private bool _plcCommOk, _plcEmoActive, _plcServoErr, _plcWdTimeout, _plcRun;
 48→    private byte _plcHeartbeat;
 49→
 50→    public bool PlcCommOk { get => _plcCommOk; set { _plcCommOk = value; OnPropertyChanged(); } }
 51→    public bool PlcEmoActive { get => _plcEmoActive; set { _plcEmoActive = value; OnPropertyChanged(); } }
 52→    public bool PlcServoErr { get => _plcServoErr; set { _plcServoErr = value; OnPropertyChanged(); } }
 53→    public bool PlcWdTimeout { get => _plcWdTimeout; set { _plcWdTimeout = value; OnPropertyChanged(); } }
 54→    public bool PlcRun { get => _plcRun; set { _plcRun = value; OnPropertyChanged(); } }
 55→    public byte PlcHeartbeat { get => _plcHeartbeat; set { _plcHeartbeat = value; OnPropertyChanged(); } }
 56→
 57→    // 연결 상태
 58→    private string _connectionStatus = "미연결";
 59→    private bool _isConnected;
 60→    private int _cycleMs;
 61→
 62→    public string ConnectionStatus { get => _connectionStatus; set { _connectionStatus = value; OnPropertyChanged(); } }
 63→    public bool IsConnected { get => _isConnected; set { _isConnected = value; OnPropertyChanged(); } }
 64→    public int CycleMs { get => _cycleMs; set { _cycleMs = value; OnPropertyChanged(); } }
 65→
 66→    // 디버그 로그 — 배치 업데이트로 UI 부하 최소화
 67→    private readonly StringBuilder _logDisplay = new();
 68→    private readonly StringBuilder _logPending = new();
 69→    private readonly object _logLock = new();
 70→    private const int MAX_LOG_CHARS = 50000;
 71→    private string _logText = "";
 72→    private bool _isLogEnabled = true;
 73→
 74→    public string LogText { get => _logText; set { _logText = value; OnPropertyChanged(); } }
 75→    public bool IsLogEnabled { get => _isLogEnabled; set { _isLogEnabled = value; OnPropertyChanged(); OnPropertyChanged(nameof(LogButtonText)); } }
 76→    public string LogButtonText => IsLogEnabled ? "로그 중지" : "로그 시작";
 77→
 78→    public IoMonitorViewModel()
 79→    {
 80→        _client.OnLog = AppendLog;
 81→
 82→        foreach (var w in MemoryMapDefinition.InputMap)
 83→            InputWords.Add(new WordViewModel(w));
 84→
 85→        foreach (var w in MemoryMapDefinition.OutputMap)
 86→            OutputWords.Add(new WordViewModel(w));
 87→
 88→        foreach (var w in MemoryMapDefinition.ServoAndSystemMap)
 89→            ServoSystemWords.Add(new WordViewModel(w));
 90→
 91→        // JSON에서 사용자 편집 이름 로드
 92→        IoMapConfig.Load(InputWords, OutputWords, ServoSystemWords);
 93→    }
 94→
 95→    /// <summary>
 96→    /// 사용자 편집 이름 JSON 저장
 97→    /// </summary>
 98→    public void SaveBitNames()
 99→    {
100→        IoMapConfig.Save(InputWords, OutputWords, ServoSystemWords);
101→    }
102→
103→    public async Task ConnectAndStartAsync()
104→    {
105→        ConnectionStatus = "연결 중...";
106→        var ok = await _client.ConnectAsync();
107→        if (!ok)
108→        {
109→            ConnectionStatus = $"연결 실패 ({_client.IpAddress}:{_client.Port})";
110→            IsConnected = false;
111→            return;
112→        }
113→
114→        IsConnected = true;
115→        ConnectionStatus = $"연결됨 ({_client.IpAddress})";
116→
117→        _cts = new CancellationTokenSource();
118→        _ = Task.Run(() => PollLoopAsync(_cts.Token));
119→    }
120→
121→    public async void StopAndDisconnect()
122→    {
123→        _cts?.Cancel();
124→
125→        // PC_READY OFF 전송 후 해제
126→        if (_client.IsConnected)
127→        {
128→            try { await _client.WriteWordsAsync("%MW500", [0]); }
129→            catch { /* 무시 */ }
130→        }
131→
132→        _client.Disconnect();
133→        IsConnected = false;
134→        PlcCommOk = false;
135→        PlcRun = false;
136→        ConnectionStatus = "미연결";
137→    }
138→
139→    /// <summary>
140→    /// 출력 비트 토글 — 클릭 시 호출
141→    /// </summary>
142→    public async Task ToggleOutputBitAsync(int wordIndex, int bitIndex)
143→    {
144→        if (!IsConnected || wordIndex < 0 || wordIndex >= 10) return;
145→
146→        // 현재 캐시 값에서 비트 토글
147→        _outputCache[wordIndex] ^= (ushort)(1 << bitIndex);
148→
149→        // 해당 WORD 1개만 쓰기 (MW200 + wordIndex)
150→        var address = $"%MW{200 + wordIndex}";
151→        await _client.WriteWordsAsync(address, [_outputCache[wordIndex]]);
152→    }
153→
154→    /// <summary>
155→    /// 주기적으로 PLC MW 영역 읽기 + Heartbeat 쓰기
156→    /// </summary>
157→    private async Task PollLoopAsync(CancellationToken ct)
158→    {
159→        while (!ct.IsCancellationRequested)
160→        {
161→            var sw = System.Diagnostics.Stopwatch.StartNew();
162→            try
163→            {
164→                // ★ Heartbeat 쓰기 — 매 사이클 최우선 (연결 중 무조건)
165→                _heartbeatCount++;
166→                ushort heartbeat = (ushort)(_heartbeatCount | 0x0100); // bit8=PC_READY
167→                await _client.WriteWordsAsync("%MW500", [heartbeat]);
168→
169→                // 입력 읽기: MW100~109 (10 WORD)
170→                var inputs = await _client.ReadWordsAsync("%MW100", 10);
171→                if (inputs != null)
172→                    UpdateWordViewModels(InputWords, inputs);
173→
174→                // 출력 읽기: MW200~209 (10 WORD) — readback
175→                var outputs = await _client.ReadWordsAsync("%MW200", 10);
176→                if (outputs != null)
177→                {
178→                    // 출력 캐시 동기화 (PLC에서 읽은 값 반영)
179→                    Array.Copy(outputs, _outputCache, Math.Min(outputs.Length, 10));
180→                    UpdateWordViewModels(OutputWords, outputs);
181→                }
182→
183→                // 서보 명령 읽기: MW300~301 (2 WORD)
184→                var servoCmds = await _client.ReadWordsAsync("%MW300", 2);
185→
186→                // 서보 파라미터 읽기: MW310~319 (10 WORD)
187→                var servoParams = await _client.ReadWordsAsync("%MW310", 10);
188→
189→                // 서보 상태 읽기: MW400~401 (2 WORD)
190→                var servoStatus = await _client.ReadWordsAsync("%MW400", 2);
191→
192→                // 서보 값 읽기: MW410~415 (6 WORD)
193→                var servoValues = await _client.ReadWordsAsync("%MW410", 6);
194→
195→                // 시스템 읽기: MW500~501 (2 WORD)
196→                var system = await _client.ReadWordsAsync("%MW500", 2);
197→
198→                // MW501 파싱 — PLC 상태 비트 + PLC 하트비트
199→                if (system is { Length: >= 2 })
200→                {
201→                    var mw501 = system[1];
202→                    Application.Current?.Dispatcher.Invoke(() =>
203→                    {
204→                        PlcCommOk = (mw501 & 0x0001) != 0;
205→                        PlcEmoActive = (mw501 & 0x0002) != 0;
206→                        PlcServoErr = (mw501 & 0x0004) != 0;
207→                        PlcWdTimeout = (mw501 & 0x0008) != 0;
208→                        PlcRun = (mw501 & 0x0010) != 0;
209→                        PlcHeartbeat = (byte)(mw501 >> 8);
210→                    });
211→                }
212→
213→                // 서보/시스템 탭 업데이트
214→                var servoSysData = new ushort[6];
215→                if (servoCmds != null) { servoSysData[0] = servoCmds[0]; servoSysData[1] = servoCmds[1]; }
216→                if (servoStatus != null) { servoSysData[2] = servoStatus[0]; servoSysData[3] = servoStatus[1]; }
217→                if (system != null) { servoSysData[4] = system[0]; servoSysData[5] = system[1]; }
218→                UpdateWordViewModels(ServoSystemWords, servoSysData);
219→
220→                // 서보 파라미터/값 (DINT) 업데이트
221→                if (servoParams is { Length: >= 6 })
222→                {
223→                    Application.Current?.Dispatcher.Invoke(() =>
224→                    {
225→                        TargetPos = (int)(servoParams[0] | (servoParams[1] << 16));
226→                        TargetVel = (int)(servoParams[2] | (servoParams[3] << 16));
227→                        JogVel = (int)(servoParams[4] | (servoParams[5] << 16));
228→                    });
229→                }
230→                if (servoValues is { Length: >= 6 })
231→                {
232→                    Application.Current?.Dispatcher.Invoke(() =>
233→                    {
234→                        ActPos = (int)(servoValues[0] | (servoValues[1] << 16));
235→                        ActVel = (int)(servoValues[2] | (servoValues[3] << 16));
236→                        ErrCode = servoValues[4];
237→                        ActPosDeg = servoValues[5];
238→                    });
239→                }
240→
241→                sw.Stop();
242→                Application.Current?.Dispatcher.Invoke(() =>
243→                {
244→                    CycleMs = (int)sw.ElapsedMilliseconds;
245→                    var plcSts = PlcRun ? "RUN" : (PlcWdTimeout ? "WD!" : "---");
246→                    ConnectionStatus = $"연결됨 ({_client.IpAddress}) — {CycleMs}ms | PC:{_heartbeatCount} PLC:{PlcHeartbeat} | {plcSts}";
247→                });
248→            }
249→            catch (Exception ex)
250→            {
251→                Application.Current?.Dispatcher.Invoke(() =>
252→                {
253→                    ConnectionStatus = $"통신 에러: {ex.Message}";
254→                });
255→            }
256→
257→            FlushLog();
258→            // Delay 없음 — 통신 사이클(~50ms) 자체가 주기
259→await Task.Yield();
260→        }
261→    }
262→
263→    private void UpdateWordViewModels(ObservableCollection<WordViewModel> vms, ushort[] data)
264→    {
265→        Application.Current?.Dispatcher.Invoke(() =>
266→        {
267→            for (int i = 0; i < Math.Min(vms.Count, data.Length); i++)
268→                vms[i].UpdateValue(data[i]);
269→        });
270→    }
271→
272→    private void AppendLog(string message)
273→    {
274→        if (!IsLogEnabled) return;
275→        lock (_logLock)
276→        {
277→            _logPending.AppendLine(message);
278→        }
279→    }
280→
281→    private void FlushLog()
282→    {
283→        string? pending;
284→        lock (_logLock)
285→        {
286→            if (_logPending.Length == 0) return;
287→            pending = _logPending.ToString();
288→            _logPending.Clear();
289→        }
290→
291→        Application.Current?.Dispatcher.BeginInvoke(() =>
292→        {
293→            _logDisplay.Append(pending);
294→
295→            if (_logDisplay.Length > MAX_LOG_CHARS)
296→            {
297→                var text = _logDisplay.ToString();
298→                var cutIndex = text.IndexOf('\n', text.Length / 2);
299→                if (cutIndex > 0)
300→                {
301→                    _logDisplay.Clear();
302→                    _logDisplay.Append(text, cutIndex + 1, text.Length - cutIndex - 1);
303→                }
304→            }
305→
306→            LogText = _logDisplay.ToString();
307→        });
308→    }
309→
310→    public void ToggleLog() => IsLogEnabled = !IsLogEnabled;
311→
312→    public void ClearLog()
313→    {
314→        lock (_logLock) { _logPending.Clear(); }
315→        _logDisplay.Clear();
316→        LogText = "";
317→    }
318→
319→    public void Dispose()
320→    {
321→        StopAndDisconnect();
322→        _client.Dispose();
323→    }
324→
325→    public event PropertyChangedEventHandler? PropertyChanged;
326→    protected void OnPropertyChanged([CallerMemberName] string? name = null)
327→        => PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(name));
328→}
329→
330→/// <summary>
331→/// 개별 WORD의 16비트 상태 뷰모델
332→/// </summary>
333→public class WordViewModel : INotifyPropertyChanged
334→{
335→    public string MwAddress { get; }
336→    public string Description { get; }
337→    public string Direction { get; }
338→    public ObservableCollection<BitViewModel> Bits { get; } = [];
339→
340→    private ushort _rawValue;
341→    public ushort RawValue { get => _rawValue; set { _rawValue = value; OnPropertyChanged(); OnPropertyChanged(nameof(HexValue)); } }
342→    public string HexValue => $"0x{RawValue:X4}";
343→
344→    public WordViewModel(WordInfo info)
345→    {
346→        MwAddress = info.MwAddress;
347→        Description = info.Description;
348→        Direction = info.Direction;
349→
350→        foreach (var bit in info.Bits)
351→            Bits.Add(new BitViewModel(bit));
352→    }
353→
354→    public void UpdateValue(ushort value)
355→    {
356→        RawValue = value;
357→        for (int i = 0; i < Bits.Count; i++)
358→            Bits[i].IsOn = PlcMemory.GetBit(value, Bits[i].BitIndex);
359→    }
360→
361→    public event PropertyChangedEventHandler? PropertyChanged;
362→    protected void OnPropertyChanged([CallerMemberName] string? name = null)
363→        => PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(name));
364→}
365→
366→/// <summary>
367→/// 개별 비트 상태 뷰모델
368→/// </summary>
369→public class BitViewModel : INotifyPropertyChanged
370→{
371→    public int BitIndex { get; }
372→    public string Address { get; }
373→    public string Unit { get; }
374→
375→    private string _name;
