using System.Windows;
using System.Windows.Controls;

namespace AssembleMonitor.Features.IoMonitor;

public partial class IoMonitorWindow : Window
{
    private readonly IoMonitorViewModel _vm;

    public IoMonitorWindow()
    {
        InitializeComponent();
        _vm = new IoMonitorViewModel();
        DataContext = _vm;
    }

    private async void BtnConnect_Click(object sender, RoutedEventArgs e)
    {
        await _vm.ConnectAndStartAsync();
    }

    private void BtnDisconnect_Click(object sender, RoutedEventArgs e)
    {
        _vm.StopAndDisconnect();
    }

    /// <summary>
    /// 출력 비트 토글 버튼 클릭
    /// </summary>
    private async void BtnOutputToggle_Click(object sender, RoutedEventArgs e)
    {
        if (sender is not Button btn || btn.Tag is not BitViewModel bitVm) return;
        if (btn.CommandParameter is not WordViewModel wordVm) return;

        var wordIndex = _vm.OutputWords.IndexOf(wordVm);
        if (wordIndex < 0) return;

        await _vm.ToggleOutputBitAsync(wordIndex, bitVm.BitIndex);
    }

    /// <summary>
    /// 비트 이름 JSON 저장
    /// </summary>
    private void BtnSaveNames_Click(object sender, RoutedEventArgs e)
    {
        _vm.SaveBitNames();
        MessageBox.Show("이름이 저장되었습니다. (config_iomap.json)",
            "저장 완료", MessageBoxButton.OK, MessageBoxImage.Information);
    }

    protected override void OnClosed(System.EventArgs e)
    {
        _vm.Dispose();
        base.OnClosed(e);
    }
}

