using System;
using System.ComponentModel;
using System.Runtime.CompilerServices;
using System.Threading;
using System.Threading.Tasks;
using System.Windows;
using AssembleMonitor.Features.Communication;

namespace AssembleMonitor.Features.ServoTest;

/// <summary>
/// 서보 제어 패널 뷰모델
/// MW300~301(명령), MW310~313(파라미터), MW400~401(상태), MW410~414(값)
/// JOG: %UW0.9.1 직접 쓰기
/// </summary>
public class ServoControlViewModel : INotifyPropertyChanged, IDisposable
{
    private readonly XgtClient _client = new();
    private CancellationTokenSource? _cts;

    // === 상태 표시 (READ) ===
    private bool _stsMoving, _stsError, _stsRdy, _stsServoMc;
    private bool _rspHomeDone, _rspMoveDone, _rspHomeErr, _rspMoveErr, _rspResetDone;
    private int _actPos, _actVel;
    private ushort _errCode;
    private ushort _mw400Raw, _mw401Raw;

    public bool StsMoving { get => _stsMoving; set { _stsMoving = value; N(); } }
    public bool StsError { get => _stsError; set { _stsError = value; N(); } }
    public bool StsRdy { get => _stsRdy; set { _stsRdy = value; N(); } }
    public bool StsServoMc { get => _stsServoMc; set { _stsServoMc = value; N(); } }
    public bool RspHomeDone { get => _rspHomeDone; set { _rspHomeDone = value; N(); } }
    public bool RspMoveDone { get => _rspMoveDone; set { _rspMoveDone = value; N(); } }
    public bool RspHomeErr { get => _rspHomeErr; set { _rspHomeErr = value; N(); } }
    public bool RspMoveErr { get => _rspMoveErr; set { _rspMoveErr = value; N(); } }
    public bool RspResetDone { get => _rspResetDone; set { _rspResetDone = value; N(); } }
    public int ActPos { get => _actPos; set { _actPos = value; N(); N(nameof(ActPosDeg)); } }
    public int ActVel { get => _actVel; set { _actVel = value; N(); } }
    public ushort ErrCode { get => _errCode; set { _errCode = value; N(); } }
    public string ActPosDeg => $"{ActPos / 1000.0:F3}°";
    public string Mw400Hex => $"0x{_mw400Raw:X4}";
    public string Mw401Hex => $"0x{_mw401Raw:X4}";

    // === 파라미터 입력 (WRITE) ===
    private string _targetPosText = "0";
    private string _targetVelText = "10000";
    private bool _isMoveRel;

    public string TargetPosText { get => _targetPosText; set { _targetPosText = value; N(); } }
    public string TargetVelText { get => _targetVelText; set { _targetVelText = value; N(); } }
    public bool IsMoveRel { get => _isMoveRel; set { _isMoveRel = value; N(); } }

    // === 연결 상태 ===
    private string _connStatus = "미연결";
    private bool _isConnected;
    private int _cycleMs;
    private string _lastCmd = "";

    public string ConnStatus { get => _connStatus; set { _connStatus = value; N(); } }
    public bool IsConnected { get => _isConnected; set { _isConnected = value; N(); } }
    public int CycleMs { get => _cycleMs; set { _cycleMs = value; N(); } }
    public string LastCmd { get => _lastCmd; set { _lastCmd = value; N(); } }

    // === 연결/해제 ===
    public async Task ConnectAsync()
    {
        ConnStatus = "연결 중...";
        if (!await _client.ConnectAsync())
        {
            ConnStatus = "연결 실패";
            return;
        }
        IsConnected = true;
        ConnStatus = "연결됨";
        _cts = new CancellationTokenSource();
        _ = Task.Run(() => PollLoopAsync(_cts.Token));
    }

    public void Disconnect()
    {
        _cts?.Cancel();
        _client.Disconnect();
        IsConnected = false;
        ConnStatus = "미연결";
    }

    // === 서보 명령 (MW300 비트 토글) ===
    public async Task CmdHomeAsync()
    {
        LastCmd = "원점복귀 실행...";
        await WriteMw300Bit(0, true);
    }

    public async Task CmdMoveAsync()
    {
        if (!int.TryParse(TargetPosText, out var pos) ||
            !int.TryParse(TargetVelText, out var vel))
        {
            LastCmd = "파라미터 입력 오류 (정수 필요)";
            return;
        }

        // MW301.1: 절대/상대
        ushort mw301 = (ushort)(IsMoveRel ? 0x0002 : 0x0000);
        await _client.WriteWordsAsync("%MW301", [mw301]);

        // MW310~313: 위치(DINT) + 속도(DINT)
        ushort posL = (ushort)(pos & 0xFFFF);
        ushort posH = (ushort)((pos >> 16) & 0xFFFF);
        ushort velL = (ushort)(vel & 0xFFFF);
        ushort velH = (ushort)((vel >> 16) & 0xFFFF);
        await _client.WriteWordsAsync("%MW310", [posL, posH, velL, velH]);

        LastCmd = $"이동: pos={pos}, vel={vel}, {(IsMoveRel ? "상대" : "절대")}";
        await WriteMw300Bit(1, true);
    }

    public async Task CmdStopAsync()
    {
        LastCmd = "즉시정지";
        await WriteMw300Bit(4, true);
    }

    public async Task CmdResetAsync()
    {
        LastCmd = "에러 리셋";
        await WriteMw300Bit(5, true);
    }

    /// <summary>
    /// 모든 명령 비트 OFF (MW300 = 0)
    /// </summary>
    public async Task CmdClearAsync()
    {
        await _client.WriteWordsAsync("%MW300", [0]);
        LastCmd = "명령 클리어 (MW300=0)";
    }

    // === JOG (%UW0.9.1 직접 쓰기) ===
    public async Task JogCwAsync(bool on)
    {
        ushort val = (ushort)(on ? 0x0001 : 0x0000);
        await _client.WriteWordsAsync("%UW0.9.1", [val]);
        LastCmd = on ? "JOG CW ON" : "JOG OFF";
    }

    public async Task JogCcwAsync(bool on)
    {
        ushort val = (ushort)(on ? 0x0002 : 0x0000);
        await _client.WriteWordsAsync("%UW0.9.1", [val]);
        LastCmd = on ? "JOG CCW ON" : "JOG OFF";
    }

    // === 폴링 루프 ===
    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            var sw = System.Diagnostics.Stopwatch.StartNew();
            try
            {
                // 서보 상태 비트: MW400~401
                var sts = await _client.ReadWordsAsync("%MW400", 2);
                if (sts is { Length: >= 2 })
                {
                    Dispatch(() =>
                    {
                        _mw400Raw = sts[0]; _mw401Raw = sts[1];
                        StsMoving = (sts[0] & 0x0001) != 0;
                        StsError = (sts[0] & 0x0002) != 0;
                        StsRdy = (sts[0] & 0x0010) != 0;
                        StsServoMc = (sts[0] & 0x0040) != 0;
                        RspHomeDone = (sts[1] & 0x0001) != 0;
                        RspMoveDone = (sts[1] & 0x0002) != 0;
                        RspHomeErr = (sts[1] & 0x0004) != 0;
                        RspMoveErr = (sts[1] & 0x0008) != 0;
                        RspResetDone = (sts[1] & 0x0010) != 0;
                        N(nameof(Mw400Hex)); N(nameof(Mw401Hex));
                    });
                }

                // 서보 값: MW410~414
                var vals = await _client.ReadWordsAsync("%MW410", 5);
                if (vals is { Length: >= 5 })
                {
                    Dispatch(() =>
                    {
                        ActPos = (int)(vals[0] | (vals[1] << 16));
                        ActVel = (int)(vals[2] | (vals[3] << 16));
                        ErrCode = vals[4];
                    });
                }

                sw.Stop();
                Dispatch(() => CycleMs = (int)sw.ElapsedMilliseconds);
            }
            catch { /* 통신 에러 무시 — 다음 사이클 재시도 */ }

            await Task.Delay(100, ct).ConfigureAwait(false);
        }
    }

    // === 유틸 ===
    private async Task WriteMw300Bit(int bit, bool on)
    {
        if (!IsConnected) return;
        var words = await _client.ReadWordsAsync("%MW300", 1);
        ushort val = (words is { Length: > 0 }) ? words[0] : (ushort)0;
        if (on) val |= (ushort)(1 << bit);
        else val &= (ushort)~(1 << bit);
        await _client.WriteWordsAsync("%MW300", [val]);
    }

    private static void Dispatch(Action a) => Application.Current?.Dispatcher.Invoke(a);

    public void Dispose()
    {
        Disconnect();
        _client.Dispose();
    }

    public event PropertyChangedEventHandler? PropertyChanged;
    private void N([CallerMemberName] string? n = null)
        => PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(n));
}

